export const GENERATED_QUESTIONS_3: SeedQuestion[] = [
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":1,"stem":"A researcher records how a plant's height changes based on the number of days since it was planted. In this study, which is the independent variable?","options":["The plant's height","Number of days since planting","The type of soil used","The amount of water given"],"correct":[1],"explanation":"The independent variable is the one that is changed or that drives the change; the dependent variable responds to it. Here height depends on time, so the number of days is the independent variable and the plant's height is the dependent variable."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":2,"stem":"A store tracks its monthly profit based on the amount of money it spends on advertising each month. Which variable is the dependent variable?","options":["Monthly profit","The month of the year","Advertising spending","The number of employees"],"correct":[0],"explanation":"The dependent variable is the outcome being measured, which depends on another variable. Profit depends on advertising spending, so profit is the dependent variable and advertising spending is the independent variable."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":2,"stem":"For a fixed driving distance, as a car's speed increases, the time needed to complete the trip decreases. What type of relationship does this describe between speed and time?","options":["No relationship","Equal relationship","Inverse relationship","Direct relationship"],"correct":[2],"explanation":"In a direct relationship both quantities increase together; in an inverse relationship one increases while the other decreases. Since higher speed leads to lower time, this is an inverse relationship."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Explain the Relationship Between Variables","difficulty":1,"stem":"At a constant price per pound, the total cost of apples increases as the number of pounds purchased increases. This is an example of what kind of relationship?","options":["Negative relationship","Direct relationship","Inverse relationship","No relationship"],"correct":[1],"explanation":"When two quantities increase together, they have a direct relationship. As pounds purchased go up, total cost goes up, so cost and weight have a direct relationship."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":1,"stem":"The frequency table below shows the number of pets owned by households surveyed.\nPets | Households\n0 | 5\n1 | 8\n2 | 3\n3 | 1\nWhat is the mode of the number of pets owned?","options":["2","8","0","1"],"correct":[3],"explanation":"The mode is the data value that occurs most often, which is the value with the highest frequency. The frequency 8 is the largest, and it belongs to the value 1 pet, so the mode is 1. (8 is the frequency, not the data value.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":3,"stem":"The frequency table below shows quiz scores for a class of 10 students.\nScore | Frequency\n70 | 2\n80 | 3\n90 | 4\n100 | 1\nWhat is the median score?","options":["87.5","80","90","85"],"correct":[3],"explanation":"Listing the 10 scores in order: 70, 70, 80, 80, 80, 90, 90, 90, 90, 100. With 10 values the median is the average of the 5th and 6th values, which are 80 and 90. The median is (80 + 90) / 2 = 85."},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":2,"stem":"The frequency table below shows goals scored by a team across 10 games.\nGoals | Games\n0 | 2\n1 | 4\n2 | 3\n3 | 1\nWhat is the mean number of goals per game?","options":["1.5","1.3","13","2"],"correct":[1],"explanation":"Multiply each value by its frequency and add: (0)(2) + (1)(4) + (2)(3) + (3)(1) = 0 + 4 + 6 + 3 = 13 total goals. Divide by the total of 10 games: 13 / 10 = 1.3. (13 is the total, not the mean.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","difficulty":2,"stem":"The frequency table below shows a set of data values and how often each occurs.\nValue | Frequency\n1 | 1\n2 | 2\n3 | 3\n4 | 4\nWhat is the mean of the data set?","options":["2.5","10","3","3.5"],"correct":[2],"explanation":"Multiply each value by its frequency and add: (1)(1) + (2)(2) + (3)(3) + (4)(4) = 1 + 4 + 9 + 16 = 30. The total number of data values is 1 + 2 + 3 + 4 = 10. The mean is 30 / 10 = 3. (2.5 is the average of just the four values 1, 2, 3, 4.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"An L-shaped figure is formed by starting with a rectangle 8 cm wide and 10 cm tall, then removing a 3 cm by 4 cm rectangular piece from one corner. What is the area of the remaining L-shaped figure? (Area of a rectangle = length × width.)","options":["56 cm²","92 cm²","68 cm²","80 cm²"],"correct":[2],"explanation":"Find the full rectangle's area: 8 × 10 = 80 cm². Find the removed piece: 3 × 4 = 12 cm². Subtract: 80 − 12 = 68 cm². (80 forgets to remove the piece; 92 incorrectly adds it.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":3,"stem":"A composite figure consists of a rectangle 10 cm long and 6 cm wide with a semicircle attached to one of the 6 cm ends. The semicircle's diameter equals 6 cm. Using π ≈ 3.14, what is the total area of the figure? (Area of a circle = πr².)","options":["60 cm²","74.13 cm²","116.52 cm²","88.26 cm²"],"correct":[1],"explanation":"Rectangle area = 10 × 6 = 60 cm². The semicircle has radius r = 6 / 2 = 3 cm, so its area = (1/2)πr² = (1/2)(3.14)(3²) = (1/2)(3.14)(9) = 14.13 cm². Total = 60 + 14.13 = 74.13 cm². (88.26 uses a full circle; 116.52 uses the diameter 6 as the radius; 60 forgets the semicircle.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"An L-shaped garden has six straight sides. Going around the edge, the side lengths in order are 6 m, 2 m, 3 m, 3 m, 3 m, and 5 m. What is the perimeter of the garden?","options":["21 m","20 m","24 m","22 m"],"correct":[3],"explanation":"Perimeter is the total distance around the figure, so add all six side lengths: 6 + 2 + 3 + 3 + 3 + 5 = 22 m. (21 m is the area of this figure, not its perimeter.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A closed rectangular box has length 5 cm, width 3 cm, and height 4 cm. What is its total surface area? (box SA = 2(lw + lh + wh).)","options":["70 cm²","47 cm²","60 cm²","94 cm²"],"correct":[3],"explanation":"Apply box SA = 2(lw + lh + wh) = 2((5)(3) + (5)(4) + (3)(4)) = 2(15 + 20 + 12) = 2(47) = 94 cm². (47 forgets to multiply by 2; 60 is the volume 5 × 3 × 4.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A closed rectangular carton measures 8 in by 4 in by 2 in. What is its total surface area? (box SA = 2(lw + lh + wh).)","options":["112 in²","100 in²","56 in²","64 in²"],"correct":[0],"explanation":"Apply box SA = 2(lw + lh + wh) = 2((8)(4) + (8)(2) + (4)(2)) = 2(32 + 16 + 8) = 2(56) = 112 in². (56 forgets to multiply by 2; 64 is the volume 8 × 4 × 2.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":3,"stem":"A cylinder has a radius of 3 cm and a height of 10 cm. Using π ≈ 3.14, what is its total surface area? (cylinder SA = 2πr² + 2πrh.)","options":["188.4 cm²","273.18 cm²","244.92 cm²","216.66 cm²"],"correct":[2],"explanation":"Apply cylinder SA = 2πr² + 2πrh. The two circular ends: 2(3.14)(3²) = 2(3.14)(9) = 56.52 cm². The side (lateral) surface: 2(3.14)(3)(10) = 188.4 cm². Total = 56.52 + 188.4 = 244.92 cm². (188.4 counts only the side; 216.66 forgets one circular end.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":3,"stem":"A cylindrical can has a diameter of 10 cm and a height of 4 cm. Using π ≈ 3.14, what is its total surface area? (cylinder SA = 2πr² + 2πrh.)","options":["879.2 cm²","282.6 cm²","408.2 cm²","125.6 cm²"],"correct":[1],"explanation":"First find the radius: r = diameter / 2 = 10 / 2 = 5 cm. Then SA = 2πr² + 2πrh = 2(3.14)(5²) + 2(3.14)(5)(4) = 2(3.14)(25) + 2(3.14)(20) = 157 + 125.6 = 282.6 cm². (879.2 wrongly uses the diameter 10 as the radius; 125.6 counts only the side.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":1,"stem":"A storage box is 6 cm long, 4 cm wide, and 5 cm tall. What is its volume? (V = L × W × H.)","options":["120 cm³","74 cm³","15 cm³","148 cm³"],"correct":[0],"explanation":"Apply V = L × W × H = 6 × 4 × 5 = 120 cm³. (148 is the surface area 2(24 + 30 + 20); 15 is just the sum of the dimensions.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"A cylinder has a radius of 2 cm and a height of 7 cm. Using π ≈ 3.14, what is its volume? (V = πr²h.)","options":["43.96 cm³","28 cm³","87.92 cm³","175.84 cm³"],"correct":[2],"explanation":"Apply V = πr²h = (3.14)(2²)(7) = (3.14)(4)(7) = (3.14)(28) = 87.92 cm³. (43.96 forgets to square the radius and uses 3.14 × 2 × 7; 28 forgets to multiply by π.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":3,"stem":"A cylindrical tank has a diameter of 6 m and a height of 10 m. Using π ≈ 3.14, what is its volume? (V = πr²h.)","options":["188.4 m³","1130.4 m³","282.6 m³","94.2 m³"],"correct":[2],"explanation":"First find the radius: r = diameter / 2 = 6 / 2 = 3 m. Then V = πr²h = (3.14)(3²)(10) = (3.14)(9)(10) = 282.6 m³. (1130.4 wrongly uses the diameter 6 as the radius; 94.2 forgets to square the radius.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"Two triangles are similar. The smaller triangle has sides 3 cm, 4 cm, and 5 cm. The larger triangle is created using a scale factor of 4. What is the perimeter of the larger triangle?","options":["48 cm","12 cm","60 cm","24 cm"],"correct":[0],"explanation":"With a scale factor of 4, each side of the larger triangle is 4 times the matching smaller side: 12 cm, 16 cm, and 20 cm. The perimeter is 12 + 16 + 20 = 48 cm. (You can also find the small perimeter 3 + 4 + 5 = 12 and multiply by 4 to get 48. The answer 12 is only the smaller triangle's perimeter.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Calculate Geometric Quantities","difficulty":2,"stem":"On a map, 1 cm represents 15 km. Two cities are 8 cm apart on the map. What is the actual distance between the cities?","options":["120 km","1.875 km","23 km","15 km"],"correct":[0],"explanation":"Multiply the map distance by the scale: 8 cm × 15 km per cm = 120 km. (23 km adds 8 and 15; 1.875 km divides instead of multiplying.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":1,"stem":"Convert 25°C to degrees Fahrenheit using °F = (9/5)°C + 32.","options":["45°F","57°F","77°F","-3.9°F"],"correct":[2],"explanation":"Apply °F = (9/5)°C + 32 = (9/5)(25) + 32 = 45 + 32 = 77°F. (45 forgets to add 32; -3.9 uses the wrong direction formula (5/9)(25 − 32).)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":2,"stem":"Convert 50°F to degrees Celsius using °C = (5/9)(°F − 32).","options":["10°C","122°C","27.8°C","18°C"],"correct":[0],"explanation":"Apply °C = (5/9)(°F − 32) = (5/9)(50 − 32) = (5/9)(18) = 10°C. (27.8 forgets to subtract 32 first; 122 uses the wrong direction (9/5)(50) + 32; 18 forgets to multiply by 5/9.)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":1,"stem":"Water boils at 100°C. Convert 100°C to degrees Fahrenheit using °F = (9/5)°C + 32.","options":["212°F","180°F","132°F","37.8°F"],"correct":[0],"explanation":"Apply °F = (9/5)°C + 32 = (9/5)(100) + 32 = 180 + 32 = 212°F. (180 forgets to add 32; 37.8 uses the wrong direction (5/9)(100 − 32).)"},
  {"section":"MATH","topic":"measurement-data","subtopic":"Convert Within and Between Standard and Metric Units","difficulty":3,"stem":"Normal human body temperature is 98.6°F. Convert this to degrees Celsius using °C = (5/9)(°F − 32).","options":["54.8°C","37°C","66.6°C","209.5°C"],"correct":[1],"explanation":"Apply °C = (5/9)(°F − 32) = (5/9)(98.6 − 32) = (5/9)(66.6) = 37°C. (66.6 forgets to multiply by 5/9; 209.5 uses the wrong direction (9/5)(98.6) + 32.)"},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":1,"stem":"15 is 25% of what number?","options":["3.75","75","60","40"],"correct":[2],"explanation":"If 15 is 25% of the whole, then whole = 15 ÷ 0.25 = 60. Check: 25% of 60 = 0.25 × 60 = 15."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":2,"stem":"A 20% tip on a restaurant bill came to $8. What was the amount of the bill before the tip?","options":["$40","$48","$160","$1.60"],"correct":[0],"explanation":"The tip is 20% of the bill, so bill = $8 ÷ 0.20 = $40. Check: 20% of $40 = 0.20 × 40 = $8. The $48 distractor mistakenly adds the tip to the bill."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":2,"stem":"A student answered 18 questions correctly, which was 75% of the test. How many questions were on the test?","options":["22","93","24","13.5"],"correct":[2],"explanation":"18 is 75% of the total, so total = 18 ÷ 0.75 = 24. Check: 75% of 24 = 0.75 × 24 = 18."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Solve Real World Problems Involving Percents","difficulty":3,"stem":"After a 30% discount, a jacket sold for $49. What was the original price?","options":["$63.70","$70","$163.33","$79"],"correct":[1],"explanation":"The sale price is 100% − 30% = 70% of the original, so original = $49 ÷ 0.70 = $70. Check: 70% of $70 = 0.70 × 70 = $49. Dividing by 0.30 instead gives the wrong $163.33."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":1,"stem":"Simplify the expression: 3(x + 2) − 2x","options":["5x + 6","x + 2","x + 5","x + 6"],"correct":[3],"explanation":"Distribute: 3(x + 2) = 3x + 6. Then 3x + 6 − 2x = (3x − 2x) + 6 = x + 6."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":2,"stem":"Simplify the expression: 5x − 2(x − 4)","options":["3x − 4","7x − 8","3x − 8","3x + 8"],"correct":[3],"explanation":"Distribute −2 across (x − 4): −2x + 8. Then 5x − 2x + 8 = 3x + 8. Forgetting the sign change on −2 × −4 gives the 3x − 8 distractor."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":2,"stem":"Simplify the expression: 4(2x + 3) − 3(x − 1)","options":["5x + 15","5x + 11","5x + 9","11x + 9"],"correct":[0],"explanation":"Distribute: 4(2x + 3) = 8x + 12 and −3(x − 1) = −3x + 3. Combine: (8x − 3x) + (12 + 3) = 5x + 15."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":3,"stem":"Simplify the expression: 2(3x − 5) − (4x − 7)","options":["10x − 3","2x − 13","2x − 3","2x − 17"],"correct":[2],"explanation":"Distribute: 2(3x − 5) = 6x − 10 and −(4x − 7) = −4x + 7. Combine: (6x − 4x) + (−10 + 7) = 2x − 3. Not distributing the negative to −7 gives the 2x − 17 distractor."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":1,"stem":"Solve the inequality: x + 5 < 12","options":["x < 7","x < 17","x > 7","x > 17"],"correct":[0],"explanation":"Subtract 5 from both sides: x < 12 − 5, so x < 7. No sign flip is needed because we did not multiply or divide by a negative."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":2,"stem":"Solve the inequality: −2x + 1 < 7","options":["x > 3","x > −3","x < 3","x < −3"],"correct":[1],"explanation":"Subtract 1: −2x < 6. Divide both sides by −2 and flip the sign: x > −3. Forgetting to flip gives the x < −3 distractor."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":2,"stem":"Solve the inequality: 3x − 4 ≥ 11","options":["x ≤ 5","x ≥ 21/3","x ≥ 7","x ≥ 5"],"correct":[3],"explanation":"Add 4: 3x ≥ 15. Divide by 3 (positive, no flip): x ≥ 5. Check: 3(5) − 4 = 11, which satisfies ≥ 11."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","difficulty":3,"stem":"Solve the inequality: 8 − 3x ≤ 23","options":["x ≥ 5","x ≥ −5","x ≤ −5","x ≤ 5"],"correct":[1],"explanation":"Subtract 8: −3x ≤ 15. Divide both sides by −3 and flip the sign: x ≥ −5. Forgetting to flip gives the x ≤ −5 distractor."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"If you multiply two odd numbers together, the product is always:","options":["Odd","Even","Sometimes odd and sometimes even","Zero"],"correct":[0],"explanation":"Odd × odd always gives an odd result. For example, 3 × 5 = 15 and 7 × 9 = 63, both odd. So the product is always odd."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"The sum of an even number and an odd number is always:","options":["A multiple of 4","Odd","Prime","Even"],"correct":[1],"explanation":"Even + odd is always odd. For example, 6 + 3 = 9 and 8 + 5 = 13, both odd."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"Which expression produces an odd result?","options":["4 × 7","3 + 5","9 × 3","2 + 6"],"correct":[2],"explanation":"4 × 7 = 28 (even), 3 + 5 = 8 (even), 9 × 3 = 27 (odd), 2 + 6 = 8 (even). Only odd × odd, here 9 × 3, gives an odd result."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"What is 4.8 ÷ 0.6?","options":["80","0.8","0.08","8"],"correct":[3],"explanation":"Move both decimals one place to get 48 ÷ 6 = 8. So 4.8 ÷ 0.6 = 8."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"type":"FILL_BLANK","stem":"Calculate: 5.6 ÷ 0.7 = ____","options":[],"correct":["8","8.0"],"explanation":"Move both decimals one place to make a whole-number divisor: 56 ÷ 7 = 8. So 5.6 ÷ 0.7 = 8."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"What is 0.144 ÷ 1.2?","options":["12","0.12","1.2","0.012"],"correct":[1],"explanation":"Move each decimal one place: 1.44 ÷ 12 = 0.12. So 0.144 ÷ 1.2 = 0.12."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"What value of n makes the equation 3/4 = n/20 true?","options":["16","15","9","12"],"correct":[1],"explanation":"Since 4 × 5 = 20, multiply the numerator by 5 as well: 3 × 5 = 15. So 3/4 = 15/20 and n = 15."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"What is the least common denominator of 1/6 and 3/8?","options":["48","14","24","12"],"correct":[2],"explanation":"The multiples of 6 are 6, 12, 18, 24 and of 8 are 8, 16, 24. The smallest shared multiple is 24."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"Express 2/5 as an equivalent fraction with a denominator of 35.","options":["12/35","14/35","7/35","10/35"],"correct":[1],"explanation":"Since 5 × 7 = 35, multiply the numerator by 7: 2 × 7 = 14. So 2/5 = 14/35."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"Reduce 18/24 to lowest terms.","options":["6/8","3/4","2/3","9/12"],"correct":[1],"explanation":"The greatest common factor of 18 and 24 is 6. Dividing both by 6 gives 18/24 = 3/4."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"Write 24/36 in simplest form.","options":["3/4","4/6","2/3","12/18"],"correct":[2],"explanation":"The greatest common factor of 24 and 36 is 12. Dividing both by 12 gives 24/36 = 2/3."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"Simplify 16/40 to lowest terms.","options":["2/5","4/10","1/3","8/20"],"correct":[0],"explanation":"The greatest common factor of 16 and 40 is 8. Dividing both by 8 gives 16/40 = 2/5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"stem":"Convert the mixed number 3 2/5 to an improper fraction.","options":["13/5","17/5","17/3","11/5"],"correct":[1],"explanation":"Multiply the whole number by the denominator and add the numerator: 3 × 5 + 2 = 17. Keep the denominator: 17/5."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"Write the improper fraction 23/4 as a mixed number.","options":["6 3/4","5 3/4","4 3/4","5 1/4"],"correct":[1],"explanation":"Divide 23 by 4 to get 5 with a remainder of 3. So 23/4 = 5 3/4."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":1,"type":"FILL_BLANK","stem":"Convert the mixed number 4 1/3 to an improper fraction: ____","options":[],"correct":["13/3"],"explanation":"Multiply the whole number by the denominator and add the numerator: 4 × 3 + 1 = 13. Keep the denominator: 13/3."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"What is 2/3 × 3/4 in simplest form?","options":["5/12","6/7","1/2","3/8"],"correct":[2],"explanation":"Multiply numerators and denominators: (2 × 3)/(3 × 4) = 6/12, which reduces to 1/2."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":2,"stem":"What is 3/4 ÷ 1/2?","options":["3/8","1 1/2","1 1/4","2/3"],"correct":[1],"explanation":"Dividing means multiplying by the reciprocal: 3/4 × 2/1 = 6/4 = 3/2 = 1 1/2."},
  {"section":"MATH","topic":"numbers-algebra","subtopic":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","difficulty":3,"stem":"What is 2 1/2 × 1 1/3?","options":["2 1/6","3 2/5","3 1/3","3 1/6"],"correct":[2],"explanation":"Convert to improper fractions: 5/2 × 4/3 = 20/6 = 10/3 = 3 1/3."},
];
